from agent import *from models.products import *import reXCAT = ['Alle anzeigen', 'Geschenkgutscheine', 'Hochbeete', 'Oster- & Frühjahrsdeko', 'Sortiment']def strip_namespace(data):    tmp = data.content_file + ".tmp"    out = file(tmp, "w")    for line in file(data.content_file):        line = line.replace('<ns0', '<')        line = line.replace('ns0:', '')        line = line.replace(' xmlns', ' abcde=')        out.write(line + "\n")    out.close()    os.rename(tmp, data.content_file)def remove_emoji(string):    emoji_pattern = re.compile("["                               u"\U0001F600-\U0001F64F"  # emoticons                               u"\U0001F300-\U0001F5FF"  # symbols & pictographs                               u"\U0001F680-\U0001F6FF"  # transport & map symbols                               u"\U0001F1E0-\U0001F1FF"  # flags (iOS)                               u"\U00002500-\U00002BEF"  # chinese char                               u"\U00002702-\U000027B0"                               u"\U00002702-\U000027B0"                               u"\U000024C2-\U0001F251"                               u"\U0001f926-\U0001f937"                               u"\U00010000-\U0010ffff"                               u"\u2640-\u2642"                               u"\u2600-\u2B55"                               u"\u200d"                               u"\u23cf"                               u"\u23e9"                               u"\u231a"                               u"\ufe0f"  # dingbats                               u"\u3030"                               "]+", flags=re.UNICODE)    return emoji_pattern.sub(r'', string)def run(context, session):    session.sessionbreakers = [SessionBreak(max_requests=10000)]    session.browser.use_new_parser = True    session.queue(Request('https://www.globus-baumarkt.de/'), process_frontpage, dict())def process_frontpage(data, context, session):    strip_namespace(data)    cats = data.xpath('//div[contains(@class, "dropdown-menu")]/ul/li[contains(@class, "item")]/a')    for cat in cats:        name = cat.xpath('@title').string()        if name:            name = name.strip()        url = cat.xpath('@href').string()        if name and name not in XCAT:            session.queue(Request(url), process_category, dict(cat=name))def process_category(data, context, session):    strip_namespace(data)    subcats = data.xpath('//a[contains(@class, "subcategory-item")]')    if not subcats:        process_prodlist(data, context, session)    for subcat in subcats:        name = subcat.xpath('div[contains(@class, "name")]/text()').string()        url = subcat.xpath('@href').string().strip('+%0A ').split('+')[-1]        if name and url:            session.queue(Request(url), process_category, dict(cat=context['cat']+'|'+name))def process_prodlist(data, context, session):    strip_namespace(data)    prods = data.xpath('//div[@data-product-id][not(contains(@data-product-id, ".Master"))]//a')    for prod in prods:        name = prod.xpath('@title').string()        url = prod.xpath('@href').string()        if name and url:            session.queue(Request(url), process_product, dict(context, name=name, url=url))    next_url = data.xpath('//link[@rel="next"]/@href').string()    if next_url:        session.queue(Request(next_url), process_prodlist, dict(context))def process_product(data, context, session):    strip_namespace(data)    product = Product()    product.name = context['name']    product.url = context['url']    product.category = context['cat']    product.manufacturer = data.xpath('//meta[@property="product:brand"]/@content').string()    product.ssid = data.xpath('//div[contains(@class, "product-id")]/text()').string().strip()    product.sku = data.xpath('//meta[@itemprop="sku"]/@content').string()    ean = data.xpath('//meta[contains(@itemprop, "gtin")]/@content').string()    if ean:        product.properties.append(ProductProperty(type='id.ean', value=ean))    mpn = data.xpath('//meta[@itemprop="mpn"]/@content').string()    if mpn and len(mpn) > 5:        product.properties.append(ProductProperty(type='id.manufacturer', value=mpn))    revs_cnt = data.xpath('//meta[@itemprop="ratingCount"]/@content').string()    if revs_cnt and int(revs_cnt) > 0:        context['product'] = product        process_reviews(data, context, session)def process_reviews(data, context, session):    strip_namespace(data)    product = context['product']    revs = data.xpath('//div[@id="review-tab-pane"]//div[@itemprop="review"]') or data.xpath('//div[@itemprop="review"]')    for rev in revs:        review = Review()        review.url = product.url        review.type = 'user'        title = rev.xpath('.//div[contains(@class, "title")]/h3/text()').string()        if title:            review.title = remove_emoji(title).strip()        author = rev.xpath('div[@itemprop="author"]/meta/@content').string()        if author:            author = remove_emoji(author).strip()            if author:                review.authors.append(Person(name=author, ssid=author))        date = rev.xpath('meta[@itemprop="datePublished"]/@content').string()        if date:            review.date = date.split(', ')[0]        is_verified = rev.xpath('.//div[contains(@class, "review-item-verify")]//text()').string(multiple=True)        if is_verified and is_verified.strip():            review.add_property(type='is_verified_buyer', value=True)        hlp = rev.xpath('div[contains(@class, "rating-info")]/p/text()').string()        if hlp:            hlp_yes = hlp.split(' von ')[0].strip()            if hlp_yes and hlp_yes.isdigit():                review.add_property(type='helpful_votes', value=int(hlp_yes))            hlp_total = hlp.split(' von ')[-1].split()[0].strip()            if hlp_total and hlp_total.isdigit():                review.add_property(type='not_helpful_votes', value=int(hlp_total) - int(hlp_yes))        grade_overall = rev.xpath('count(.//div[contains(@class, "point-full")])')        half_grade = rev.xpath('count(.//div[contains(@class, "point-partial-placeholder")]) div 2')        grade_overall += half_grade        if grade_overall > 0:            review.grades.append(Grade(type="overall", value=float(grade_overall), best=5.0))        excerpt = rev.xpath('p[@itemprop="description"]/text()').string(multiple=True)        if excerpt:            excerpt = remove_emoji(excerpt).strip()            if excerpt:                review.properties.append(ReviewProperty(type="excerpt", value=excerpt))                review.ssid = review.digest() if author else review.digest(excerpt)                product.reviews.append(review)    next_url = data.xpath('//li[@class="page-item page-next"]')    if next_url:        next_page = context.get('page', 1) + 1        revs_url = 'https://www.globus-baumarkt.de/product/{}/reviews?p={}'.format(product.ssid, next_page)        session.do(Request(revs_url), process_reviews, dict(product=product, page=next_page))    elif product.reviews:        session.emit(product)